SELECT COUNT(DISTINCT LPB.PK) FROM LATTES_PRODBIB LPB JOIN LATTES_P_PRODBIB LPP ON LPP.FK_PRODBIB = LPB.PK JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE (LOWER(LPB.TIPO) LIKE LOWER('%capitulo de livro%') OR LOWER(LPB.TIPO) LIKE LOWER('%capitulo de livro%') OR LOWER(LPB.NATUREZA) LIKE LOWER('%capitulo%') OR LOWER(LPB.NATUREZA) LIKE LOWER('%capitulo%')) AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%nutricao%') AND (S.SIGLA_CAMPUS = 'OES' OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania oeste%') OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania oeste%')) AND (LPB.ANO GLOB '[0-9][0-9][0-9][0-9]' AND CAST(LPB.ANO AS INTEGER) = 2021)